import debounce from 'lodash/debounce'
import throttle from 'lodash/throttle'

// Internal use only.
let hasScrolled
let header
let height
let previousOffset
let toggler

/**
 * Determines if the header needs to become sticky or not.
 */
function scrollCallback() {
  const offset = window.scrollY || document.documentElement.scrollTop

  // Sticky mode
  if (
    (
      (!hasScrolled && offset >= previousOffset) ||
      (hasScrolled && offset > previousOffset)
    ) &&
    offset > height &&
    !header.classList.contains('zv-header--stuck')
  ) {
    header.classList.add('zv-header--stuck')
    window.setNavDark(false)
  }

  // Non-sticky mode
  if (
    offset < previousOffset && offset < height * 1.5 &&
    header.classList.contains('zv-header--stuck')
  ) {
    header.classList.remove('zv-header--stuck')
    window.syncNavigationColorScheme()
  }

  hasScrolled    = true
  previousOffset = offset
}

export function NavHeight() {
  return parseFloat(window.getComputedStyle(header).height, 10)
}

export default function Navigation() {
  header         = document.querySelector('.zv-header')
  height         = parseInt(window.getComputedStyle(header).height) / 2
  previousOffset = window.screenY || document.documentElement.scrollTop || 0
  toggler        = document.querySelector('.navbar-toggler')

  // Listen for when the toggler button is pressed
  if (toggler) {
    toggler.addEventListener('click', debounce(() => {
      const method = toggler.classList.contains('collapsed') ? 'remove' : 'add'

      document.body.classList[method]('menu-open')
      header.classList[method]('zv-header--shadow')
    }, 100))
  }

  // Listen for when the user scrolls the page
  window.addEventListener('scroll', throttle(scrollCallback, 100))

  // Listen for when the page is resized
  window.addEventListener('resize', throttle(() => {
    height = parseInt(window.getComputedStyle(header).height) / 2
  }, 100))

  // Check if the header should be stuck straight away
  scrollCallback()
}



