module.exports = function(options) {
  // To do: use global constants
  const MODEL_PARTIAL_RELATION = {
    "navigation": "navigation",
    "banner": "banner",
    "campaignCollaborators": "campaign-collaborators",
    "campaignSupporters": "campaign-supporters",
    "catHackCategoryChase": "cat-hacks-list",
    "catHack": "card",
    "catHackQuote": "card",
    "catHackTip": "card",
    "catHackVideo": "card",
    "contentList": "content-list",
    "featured": "featured",
    "hero": "hero",
    "image": "post-image",
    "postParagraph": "post-paragraph",
    "postSplit": "split",
    "quote": "quote",
    "relatedContent": "related-content",
    "socialSharing": "social-sharing",
    "statistics": "stats",
    "video": "video-player",
    "form": "form",
    "formField": "form-field",
    "button": "button",
    "formSuccess": "form-success",
    "empty": "empty",
    "subscribe": "subscribe"
  }

  let modelName
  let partialName = 'empty'

  if (options.hash.modelName.sys.contentType !== undefined) {
    modelName = options.hash.modelName.sys.contentType.sys.id

    if (MODEL_PARTIAL_RELATION[modelName] !== undefined) {
      partialName = MODEL_PARTIAL_RELATION[modelName]
    }
  }

  return partialName
}



