export default function catHacksList(id, categories, data, shuffle, hacksQuantity, pageSize, share, modals) {

  const _ = require('lodash')
  let page

  function mergeHacksIntoAPage(categories, data) {
    return page = data.filter(hack => categories.indexOf(hack.fields.category) !== -1)
  }

  function shufflePage(page) {
    return _.shuffle(page)
  }

  function slicePage(page, size) {
    return page.slice(0, size)
  }

  function splitIntoPages(page, size) {
    return _.chunk(page, size)
  }

  function catHacksPages(categories, data, shuffle, hacksQuantity, pageSize) {
    // Merge the hacks into a single array
    page = mergeHacksIntoAPage(categories, data)

    // Shuffle the hacks
    if (shuffle) {
      page = shufflePage(page)
    }

    // Only keep x amount of hacks
    if (hacksQuantity) {
      page = slicePage(page, hacksQuantity)
    }

    let pages

    // Split the hacks into x pages
    if (pageSize) {
      pages = splitIntoPages(page, pageSize)
    } else {
      pages = splitIntoPages(page, page.length)
    }

    return pages
  }

  let catHacks = {
    'id': id,
    'pages': catHacksPages(categories, data, shuffle, hacksQuantity, pageSize),
    'share': share,
    'modals': modals
  }

  return catHacks
}



