export function parseJSON(input) {
  try {
    const json = JSON.parse(input)
    return json
  } catch (e) {
    console.error('Error parsing JSON input:', input, '\nError: ', e)
  }

  return {}
}

export function blogURLforModalID(modalID){
    console.log(modalID.indexOf('global'))
    if(modalID.indexOf('global') >= 0) {
      //dont change global IDs
      return window.location;
    } else {
      modalID = modalID.replace('modal-','');
      let siteURL = location.protocol + '//' + location.host + "/blog.html";
      siteURL += "?slug=" + modalID
      // console.log('id= ',modalID);
      return siteURL;
    }
}

export function modalShow(div) {
  document.body.style.overflow = 'hidden'
  document.body.style.height = '100vh'
  console.log("MODAL opened - ",div.id)
  //set the url for this
  window.history.replaceState({}, '', blogURLforModalID(div.id));
}

export function modalClosed(div) {
  document.body.style.overflow = 'auto'
  document.body.style.height   = 'auto'
  console.log("MODAL CLOSED - ",div.id)
  let path = window.location.href.split("?")[0]
  window.history.replaceState({},'',path);
  //window.location = window.urlForModalID(modalID)
}

export function whichEvent(animation = false) {
  const el = document.createElement('fakeelement');

  let name      = 'transition'
  let nameUpper = 'Transition'

  if (animation) {
    name      = 'animation'
    nameUpper = 'Animation'
  }

  const types = {
    [name]                 : `${name}end`,
    [`O${nameUpper}`]      : `o${nameUpper}End`,
    [`Moz${nameUpper}`]    : `${name}end`,
    [`Webkit${nameUpper}`] : `webkit${nameUpper}End`,
  }

  for (const t in types) {
    if (el.style[t] !== undefined) {
      return types[t];
    }
  }
}



