module.exports = function({ hash }) {
  const classes = []
  const tests   = hash.tests

  if (hash.defaults) {
    classes.push(hash.defaults)
  }

  if (tests && tests.length) {
    for (const test of tests.split('|')) {
      const [_, matchFalse, option, className] = test.match(/^(!?)(\w+):(.*)/)

      if (
        (matchFalse === '!' && !hash[option]) ||
        (!matchFalse && hash[option] === true)
      ) {
        classes.push(className)
      }
    }
  }

  // Finally, push the extra classes
  if (hash.extras) {
    classes.push(hash.extras)
  }

  return classes.filter(x => x && x.length).join(' ').trim()
}



