module.exports = function(lvalue, operator, rvalue, options) {
  switch (operator) {
    case '==':
      return (lvalue == rvalue) ? options.fn(this) : options.inverse(this);
    case '===':
      return (lvalue === rvalue) ? options.fn(this) : options.inverse(this);
    case '!=':
      return (lvalue != rvalue) ? options.fn(this) : options.inverse(this);
    case '!==':
      return (lvalue !== rvalue) ? options.fn(this) : options.inverse(this);
    case '<':
      return (lvalue < rvalue) ? options.fn(this) : options.inverse(this);
    case '<=':
      return (lvalue <= rvalue) ? options.fn(this) : options.inverse(this);
    case '>':
      return (lvalue > rvalue) ? options.fn(this) : options.inverse(this);
    case '>=':
      return (lvalue >= rvalue) ? options.fn(this) : options.inverse(this);
    case '&&':
      return (lvalue && rvalue) ? options.fn(this) : options.inverse(this);
    case '||':
      return (lvalue || rvalue) ? options.fn(this) : options.inverse(this);
    default:
      return options.inverse(this);
  }
}



